import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Plus,
  TrendingUp,
  TrendingDown,
  ArrowUpRight,
  ArrowDownRight,
  Wallet,
  Receipt,
  PieChart,
} from "lucide-react";

// =========================
// SAFE NUMBER FORMATTER
// =========================
const money = (val) => {
  const num = Number(val ?? 0);
  return isNaN(num) ? 0 : num;
};

const FinancePortal = () => {
  const user = authService.getUser() || {};

  const [payments, setPayments] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [summary, setSummary] = useState({});
  const [loading, setLoading] = useState(true);

  const [txnDialogOpen, setTxnDialogOpen] = useState(false);

  const [txnForm, setTxnForm] = useState({
    transaction_type: "income",
    category: "",
    amount: "",
    description: "",
    date: new Date().toISOString().split("T")[0],
  });

  const incomeCategories = [
    "Donations",
    "Government Grants",
    "Events",
    "Fundraising",
    "Other Income",
  ];

  const expenditureCategories = [
    "Salaries",
    "Utilities",
    "Supplies",
    "Maintenance",
    "Transport",
    "Food",
    "Equipment",
    "Other Expense",
  ];

  // =========================
  // FETCH DATA (SAFE)
  // =========================
  useEffect(() => {
    let mounted = true;

    const fetchData = async () => {
      try {
        setLoading(true);

        const [paymentsRes, txnRes, summaryRes] = await Promise.all([
          apiClient.get("/payments?approval_status=all").catch(() => ({ data: [] })),
          apiClient.get("/finance/transactions").catch(() => ({ data: [] })),
          apiClient.get("/finance/summary").catch(() => ({ data: {} })),
        ]);

        if (!mounted) return;

        setPayments(paymentsRes?.data || []);
        setTransactions(txnRes?.data || []);
        setSummary(summaryRes?.data || {});
      } catch (error) {
        console.error(error);
        toast.error("Failed to fetch finance data");
      } finally {
        if (mounted) setLoading(false);
      }
    };

    fetchData();

    return () => {
      mounted = false;
    };
  }, []);

  // =========================
  // ADD TRANSACTION
  // =========================
  const handleAddTransaction = async (e) => {
    e.preventDefault();

    try {
      await apiClient.post("/finance/transactions", {
        ...txnForm,
        amount: Number(txnForm.amount || 0),
      });

      toast.success("Transaction recorded successfully");

      setTxnDialogOpen(false);

      setTxnForm({
        transaction_type: "income",
        category: "",
        amount: "",
        description: "",
        date: new Date().toISOString().split("T")[0],
      });

      const res = await apiClient.get("/finance/transactions");
      setTransactions(res?.data || []);
    } catch (error) {
      console.error(error);
      toast.error(error?.response?.data?.detail || "Failed to record transaction");
    }
  };

  // =========================
  // LOADING STATE
  // =========================
  if (loading) {
    return (
      <div className="flex justify-center items-center py-20 text-slate-400">
        Loading finance data...
      </div>
    );
  }

  return (
    <div className="space-y-6" data-testid="finance-portal">

      {/* HEADER */}
      <div className="bg-gradient-to-r from-emerald-600/20 to-teal-600/20 border border-emerald-500/20 rounded-2xl p-8">
        <h2 className="text-4xl font-bold text-white">
          Finance Portal
        </h2>

        <p className="text-emerald-300/70 mt-2 text-lg">
          Welcome back, {user?.full_name || "User"}
        </p>

        <p className="text-emerald-400/50 text-sm mt-1">
          Income, expenditure & school fee management
        </p>
      </div>

      {/* ACTION BUTTON */}
      <div className="flex justify-end">
        <Dialog open={txnDialogOpen} onOpenChange={setTxnDialogOpen}>
          <DialogTrigger asChild>
            <Button className="bg-emerald-600 hover:bg-emerald-700">
              <Plus className="w-4 h-4 mr-2" />
              Add Transaction
            </Button>
          </DialogTrigger>

          <DialogContent>
            <DialogHeader>
              <DialogTitle>Record Transaction</DialogTitle>
            </DialogHeader>

            <form onSubmit={handleAddTransaction} className="space-y-4">

              <div className="space-y-2">
                <Label>Transaction Type</Label>

                <Select
                  value={txnForm.transaction_type}
                  onValueChange={(v) =>
                    setTxnForm({
                      ...txnForm,
                      transaction_type: v,
                      category: "",
                    })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>

                  <SelectContent>
                    <SelectItem value="income">Income</SelectItem>
                    <SelectItem value="expenditure">Expenditure</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Category</Label>

                <Select
                  value={txnForm.category}
                  onValueChange={(v) =>
                    setTxnForm({ ...txnForm, category: v })
                  }
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select category" />
                  </SelectTrigger>

                  <SelectContent>
                    {(txnForm.transaction_type === "income"
                      ? incomeCategories
                      : expenditureCategories
                    ).map((c) => (
                      <SelectItem key={c} value={c}>
                        {c}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Amount (KES)</Label>

                <Input
                  type="number"
                  value={txnForm.amount}
                  onChange={(e) =>
                    setTxnForm({ ...txnForm, amount: e.target.value })
                  }
                />
              </div>

              <div className="space-y-2">
                <Label>Description</Label>

                <Textarea
                  value={txnForm.description}
                  onChange={(e) =>
                    setTxnForm({ ...txnForm, description: e.target.value })
                  }
                />
              </div>

              <Button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700">
                Save Transaction
              </Button>

            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* SUMMARY CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-6">
            <p className="text-slate-400">Total Income</p>
            <p className="text-emerald-400 text-2xl font-bold">
              KES {money(summary?.total_income).toLocaleString()}
            </p>
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-6">
            <p className="text-slate-400">Total Expenditure</p>
            <p className="text-red-400 text-2xl font-bold">
              KES {money(summary?.total_expenditure).toLocaleString()}
            </p>
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-6">
            <p className="text-slate-400">Balance</p>
            <p className="text-blue-400 text-2xl font-bold">
              KES {money(summary?.running_balance).toLocaleString()}
            </p>
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-6">
            <p className="text-slate-400">Fee Income</p>
            <p className="text-amber-400 text-2xl font-bold">
              KES {money(summary?.total_fee_income).toLocaleString()}
            </p>
          </CardContent>
        </Card>

      </div>

      {/* TRANSACTIONS */}
      <Tabs defaultValue="transactions">
        <TabsList className="bg-[#0F1A2A]">
          <TabsTrigger value="transactions">Transactions</TabsTrigger>
          <TabsTrigger value="payments">Payments</TabsTrigger>
        </TabsList>

        <TabsContent value="transactions">
          <Card className="bg-[#1A2332] border-[#1E293B]">
            <CardContent className="p-4">

              {transactions.length === 0 ? (
                <div className="text-center py-10 text-slate-500">
                  No transactions yet
                </div>
              ) : (
                <div className="overflow-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Date</TableHead>
                        <TableHead>Type</TableHead>
                        <TableHead>Category</TableHead>
                        <TableHead>Amount</TableHead>
                      </TableRow>
                    </TableHeader>

                    <TableBody>
                      {transactions.map((t, i) => (
                        <TableRow key={t?.id || i}>
                          <TableCell>
                            {t?.date ? new Date(t.date).toLocaleDateString() : "—"}
                          </TableCell>
                          <TableCell>{t?.transaction_type}</TableCell>
                          <TableCell>{t?.category}</TableCell>
                          <TableCell>
                            {money(t?.amount).toLocaleString()}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}

            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="payments">
          <Card className="bg-[#1A2332] border-[#1E293B]">
            <CardContent className="p-4">

              {payments.length === 0 ? (
                <div className="text-center py-10 text-slate-500">
                  No payments found
                </div>
              ) : (
                <div className="overflow-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Receipt</TableHead>
                        <TableHead>Amount</TableHead>
                        <TableHead>Status</TableHead>
                      </TableRow>
                    </TableHeader>

                    <TableBody>
                      {payments.map((p, i) => (
                        <TableRow key={p?.id || i}>
                          <TableCell>{p?.receipt_number || "—"}</TableCell>
                          <TableCell>KES {money(p?.amount).toLocaleString()}</TableCell>
                          <TableCell>{p?.status || "pending"}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}

            </CardContent>
          </Card>
        </TabsContent>

      </Tabs>
    </div>
  );
};

export default FinancePortal;
